import XCTest
@testable import Clave

/// Differential NIP-01 conformance test. Every event below was fetched from a
/// public relay, which only stores events whose id+sig it validated as
/// canonical -- so each is a ground-truth sample. `LightEvent.verify` MUST
/// return true for all, or Clave's serialization diverges from canonical
/// NIP-01. Diverse kinds (1/0/3/30023) deliberately stress the content-escaping
/// path (unicode/emoji/quotes/newlines/markdown) that kind:24133 base64
/// envelopes never exercise. Corpus is base64-encoded JSONL, chunked to keep
/// the Swift type-checker happy.
final class LightEventCorpusTests: XCTestCase {
    func testVerifyAcceptsRealRelayCorpus() {
        let b64 = [
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            "",
            ""
        ].joined()
        guard let data = Data(base64Encoded: b64),
              let jsonl = String(data: data, encoding: .utf8) else {
            return XCTFail("corpus fixture failed to decode")
        }
        var total = 0, failed = 0, examples: [String] = []
        for line in jsonl.split(separator: "\n") {
            guard let d = line.data(using: .utf8),
                  let ev = try? JSONSerialization.jsonObject(with: d) as? [String: Any] else { continue }
            total += 1
            if !LightEvent.verify(event: ev) {
                failed += 1
                let id = (ev["id"] as? String)?.prefix(12) ?? "?"
                let kind = ev["kind"] as? Int ?? -1
                if examples.count < 25 { examples.append("k\(kind) \(id)") }
            }
        }
        print("[corpus] verified \(total - failed)/\(total) real relay events")
        XCTAssertGreaterThan(total, 60, "corpus too small (\(total))")
        XCTAssertEqual(failed, 0, "\(failed)/\(total) real canonical events FAILED verify -- serialization divergence. Examples: \(examples.joined(separator: ", "))")
    }
}
